/**
 * Route matching cache to avoid redundant iterations.
 */
const ROUTE_MATCH_CACHE_MAX = 1000;
const routeMatchCache = new Map<string, boolean>();

function setRouteMatchCache(cacheKey: string, value: boolean): void {
  if (routeMatchCache.size >= ROUTE_MATCH_CACHE_MAX) {
    const oldestKey = routeMatchCache.keys().next().value;
    if (oldestKey !== undefined) {
      routeMatchCache.delete(oldestKey);
    }
  }
  routeMatchCache.set(cacheKey, value);
}

/**
 * Check if a path matches a route pattern.
 */
export function matchRoute(pattern: string, path: string): boolean {
  const cacheKey = `${pattern}:${path}`;
  if (routeMatchCache.has(cacheKey)) {
    return routeMatchCache.get(cacheKey)!;
  }

  const patternParts = pattern.split('/').filter(Boolean);
  const pathParts = path.split('/').filter(Boolean);
  
  if (patternParts.length !== pathParts.length) {
    setRouteMatchCache(cacheKey, false);
    return false;
  }
  
  for (let i = 0; i < patternParts.length; i++) {
    const patternPart = patternParts[i];
    const pathPart = pathParts[i];
    
    if (!patternPart.startsWith(':') && patternPart !== pathPart) {
      setRouteMatchCache(cacheKey, false);
      return false;
    }
  }
  
  setRouteMatchCache(cacheKey, true);
  return true;
}

/**
 * Extract parameters from a path matching a route pattern.
 */
export function extractParams<T extends RoutePath>(
  pattern: T,
  path: string
): RouteParams<T> | null {
  const patternParts = pattern.split('/').filter(Boolean);
  const pathParts = path.split('/').filter(Boolean);
  const params: Record<string, string> = {};
  
  if (patternParts.length !== pathParts.length) {
    return null;
  }
  
  for (let i = 0; i < patternParts.length; i++) {
    const patternPart = patternParts[i];
    const pathPart = pathParts[i];
    
    if (patternPart.startsWith(':')) {
      params[patternPart.slice(1)] = pathPart;
    } else if (patternPart !== pathPart) {
      return null;
    }
  }
  
  return params as RouteParams<T>;
}

/**
 * Check if a route path is active (matches current path).
 */
export function isRouteActive(path: RoutePath, currentPath: string): boolean {
  // Exact match
  if (currentPath === path) {
    return true;
  }
  
  // Prefix match for index routes
  if (path !== '/' && currentPath.startsWith(path)) {
    const nextChar = currentPath.charAt(path.length);
    return nextChar === '/' || nextChar === '';
  }
  
  return false;
}

