/**
 * Navigate to a route programmatically.
 */
export function navigate<T extends RoutePath>(
  path: T,
  ...args: [...RouteParams<T> extends never ? [] : [params: RouteParams<T>], options?: NavigateOptions]
): void {
  let url = buildRoute(path, ...(args.length > 0 && typeof args[0] === 'object' && !('replace' in args[0]) ? [args[0]] : []));
  
  const options = args.find(a => typeof a === 'object' && 'replace' in a) as NavigateOptions | undefined;
  
  if (options?.query) {
    url += buildQuery(options.query);
  }
  
  if (options?.replace) {
    window.history.replaceState(options.state ?? {}, '', url);
  } else {
    window.history.pushState(options.state ?? {}, '', url);
  }
  
  // Dispatch popstate to trigger route change
  window.dispatchEvent(new PopStateEvent('popstate'));
}

/**
 * Create a link props object for use with anchor elements.
 */
export function getLinkProps<T extends RoutePath>(
  path: T,
  ...args: [...RouteParams<T> extends never ? [] : [params: RouteParams<T>], query?: RouteQuery]
): { href: string } {
  const hasParams = path.includes(':');
  const params = hasParams && args.length > 0 && typeof args[0] === 'object' && args[0] !== null
    ? (args[0] as RouteParams<T>)
    : undefined;
  let href = buildRoute(path, ...(params ? [params] : []));
  
  const queryIndex = hasParams ? 1 : 0;
  const query = args[queryIndex] as RouteQuery | undefined;
  
  if (query && typeof query === 'object') {
    href += buildQuery(query);
  }
  
  return { href };
}

